+            return command_error_to_resp(CommandError::WrongArity("CLUSTER"));
+        }
+        let subcommand = match std::str::from_utf8(&argv[1]) {
+            Ok(subcommand) => subcommand,
+            Err(_) => return command_error_to_resp(CommandError::InvalidUtf8Argument),
+        };
